// ============================================================
// NETWORK — real-time plaza + 1v1 room sync via public MQTT (broker.emqx.io)
// ============================================================
// Player state is tracked through the Players Map (playerId/clientId ->
// player record) so the same room-sync plumbing can scale from a 1v1
// duel to a 3-4 player free-for-all later just by adding more Map
// entries — none of the netPub/topic logic is hard-wired to "two".
const BASE="rehovot-skatepark-range";
const NET={
  id:"sk_"+Math.random().toString(36).slice(2,10),
  name:"מקומי #"+(100+Math.floor(Math.random()*900)),
  mq:null, ok:false, roster:{}, room:null, isHost:false,
  oppo:null, oppoFinal:null, pendingRoom:null, posT:0, starting:false,
  inboxTopic:null, lastOppoName:null,
};
// Seed the Map with "me" so future N-player expansion only ever has to
// iterate Players.values() instead of touching G.player / NET.oppo by name.
Players.set(NET.id, { id:NET.id, name:NET.name, score:0, you:true });

const lobbyList=document.getElementById("lobbyList");
const lobbyConn=document.getElementById("lobbyConn");
const countOverlay=document.getElementById("countOverlay");
let pendingInvite=null;
function roomTopic(){ return BASE+"/room/"+NET.room; }
function cleanName(name){
  return (name||"").trim().replace(/[\/\+\#\s]+/g,"_").replace(/[^\p{L}\p{N}_\-]/gu,"").slice(0,40) || "guest";
}
function inboxTopicFor(name){ return BASE+"/player/"+cleanName(name)+"/inbox"; }
function subscribeInbox(){
  if(!NET.ok||!NET.mq) return;
  const newTopic=inboxTopicFor(NET.name);
  if(NET.inboxTopic===newTopic) return;
  if(NET.inboxTopic) NET.mq.unsubscribe(NET.inboxTopic);
  NET.mq.subscribe(newTopic,{qos:1},(err)=>{
    if(!err) console.log("[range] subscribed to inbox:",newTopic);
  });
  NET.inboxTopic=newTopic;
}
function netPub(t,o){ if(NET.ok&&NET.mq){ o.f=NET.id; o.fname=NET.name; try{NET.mq.publish(t,JSON.stringify(o));}catch(e){} } }
function setConn(on){
  lobbyConn.textContent = on ? "🟢 מחובר לפלאזה" : "אין חיבור לפלאזה";
  lobbyConn.classList.toggle("on",on);
  renderRoster();
}
function netInit(){
  if(typeof mqtt==="undefined"){ setConn(false); return; }
  const WSS_URL="wss://broker.emqx.io:8084/mqtt";
  try{
    NET.mq=mqtt.connect(WSS_URL,
      {clientId:NET.id,keepalive:30,clean:true,connectTimeout:7000,reconnectPeriod:5000});
  }catch(e){ setConn(false); return; }
  NET.mq.on("connect",()=>{
    NET.ok=true; setConn(true);
    NET.mq.subscribe(BASE+"/presence");
    subscribeInbox();
    beat();
  });
  NET.mq.on("close",()=>{ NET.ok=false; setConn(false); });
  NET.mq.on("offline",()=>{ NET.ok=false; setConn(false); });
  NET.mq.on("error",()=>{});
  NET.mq.on("message",(topic,raw)=>{
    let m; try{ m=JSON.parse(raw.toString()); }catch(e){ return; }
    if(m.f===NET.id) return;

    if(topic===BASE+"/presence"){
      NET.roster[m.f]={name:m.fname||m.name,st:m.st,ts:Date.now()};
      renderRoster();
      return;
    }

    if(NET.inboxTopic && topic===NET.inboxTopic){
      if(m.type==="CHALLENGE_INVITE"){
        if(G.mode==="play"){
          netPub(inboxTopicFor(m.challengerName),{type:"CHALLENGE_BUSY",room:m.room});
          return;
        }
        pendingInvite=m;
        showChallengeModal(m.challengerName);
      } else if(m.type==="CHALLENGE_ACCEPT"){
        if(m.room===NET.pendingRoom){
          joinRoom(m.room,true,m.responderName);
          startOverlay.classList.add("hidden");
          endOverlay.classList.add("hidden");
          countOverlay.classList.add("hidden");
          NET.pendingRoom=null;
          grindSound();
          setTimeout(()=>{
            NET.starting=true;
            const dropIn=document.getElementById("startBtn");
            if(dropIn) dropIn.click();
            NET.starting=false;
          }, 300);
        }
      } else if(m.type==="CHALLENGE_BUSY"){
        if(m.room===NET.pendingRoom) NET.pendingRoom=null;
      }
      return;
    }

    if(NET.room && topic===roomTopic()){ onRoomMsg(m); return; }
  });
}
