function beat(){ netPub(BASE+"/presence",{name:NET.name,st:G.mode==="play"?"play":"lobby"}); }
setInterval(()=>{
  if(!NET.ok) return;
  beat();
  let changed=false;
  for(const id in NET.roster) if(Date.now()-NET.roster[id].ts>9500){ delete NET.roster[id]; changed=true; }
  if(changed) renderRoster();
},3000);
function renderRoster(){
  lobbyList.innerHTML="";
  const me=document.createElement("li");
  me.className="me"; me.textContent="אתה — "+NET.name;
  lobbyList.appendChild(me);
  const ids=Object.keys(NET.roster);
  if(!ids.length){
    const li=document.createElement("li");
    li.innerHTML='<span class="st">'+(NET.ok?"הפלאזה ריקה כרגע":"אין חיבור לפלאזה")+'</span>';
    lobbyList.appendChild(li);
    refreshRematchUI();
    return;
  }
  ids.sort((a,b)=>{
    const aLast = NET.roster[a].name===NET.lastOppoName ? 1 : 0;
    const bLast = NET.roster[b].name===NET.lastOppoName ? 1 : 0;
    return bLast-aLast;
  });
  for(const id of ids){
    const p=NET.roster[id];
    const li=document.createElement("li");
    const isLastOppo = !!NET.lastOppoName && p.name===NET.lastOppoName;
    if(isLastOppo){ li.style.border="1px solid var(--brand-amber)"; li.style.background="rgba(230,169,37,.12)"; }
    const nm=document.createElement("span"); nm.textContent=(isLastOppo?"🔁 ":"")+p.name;
    const st=document.createElement("span"); st.className="st"; st.textContent=p.st==="play"?"בליין 🛹":"בפלאזה";
    const b=document.createElement("button"); b.className="chBtn"; b.textContent="הזמן לליין";
    b.disabled = p.st==="play" || !NET.ok;
    b.addEventListener("click",()=>{
      NET.pendingRoom="room_"+Date.now().toString(36)+"_"+Math.random().toString(36).slice(2,6);
      netPub(inboxTopicFor(p.name),{
        type:"CHALLENGE_INVITE",
        challengerName:NET.name,
        room:NET.pendingRoom
      });
      b.textContent="נשלח..."; b.disabled=true;
      setTimeout(()=>{ b.textContent="הזמן לליין"; b.disabled=(NET.roster[id]||{}).st==="play"; },4000);
      blip(620,0.06,"square",0.03);
    });
    li.append(nm,st,b); lobbyList.appendChild(li);
  }
  refreshRematchUI();
}
function refreshRematchUI(){
  const box=document.getElementById("rematchBox");
  if(!box) return;
  const txt=document.getElementById("rematchText");
  const oppName=NET.lastOppoName;
  const stillHere = !!oppName && Object.values(NET.roster).some(p=>p.name===oppName && p.st!=="play");
  if(G.mode==="over" && stillHere){
    box.style.display="flex";
    if(txt) txt.textContent = oppName+" עדיין נמצא בפלאזה — אפשר לאתגר אותו שוב!";
  } else {
    box.style.display="none";
  }
}
