function joinRoom(room,isHost,oppName){
  NET.room=room; NET.isHost=isHost; NET.oppoFinal=null;
  NET.oppo={px:0,py:0,score:0,name:oppName};
  // mirror into the scalable Players Map under the opponent's id slot
  Players.set("oppo_"+room, { id:"oppo_"+room, name:oppName, score:0, you:false });
  renderLiveBoard();
  NET.mq.subscribe(roomTopic());
  NET.lineNames={};
  NET.lineNames[NET.name]=true;
  NET.lineNames[oppName]=true;
  renderActiveLine();
}
function leaveRoom(){
  if(!NET.room) return;
  netPub(roomTopic(),{t:"leave",name:NET.name});
  try{ NET.mq.unsubscribe(roomTopic()); }catch(e){}
  Players.delete("oppo_"+NET.room);
  NET.room=null; NET.oppo=null; NET.oppoFinal=null;
  NET.lineNames=null;
  liveBoardEl.style.display="none";
  renderActiveLine();
}
function renderActiveLine(){
  const bar=document.getElementById("activeLineBar");
  if(!NET.room||!NET.lineNames){ bar.style.display="none"; return; }
  const names=Object.keys(NET.lineNames);
  bar.innerHTML="🔥 גולשים בליין כרגע: <b>"+names.join(", ")+"</b>";
  bar.style.display="block";
}
function countdown(){
  NET.starting=true;
  startOverlay.classList.add("hidden"); endOverlay.classList.add("hidden");
  document.getElementById("countLabel").textContent="SYNCED LINE VS "+NET.oppo.name;
  countOverlay.classList.remove("hidden");
  const num=document.getElementById("countNum");
  let n=3; num.textContent=n; thump(180,90,0.12,0.1);
  const iv=setInterval(()=>{
    n--;
    if(n>0){ num.textContent=n; thump(180,90,0.12,0.1); }
    else{
      clearInterval(iv);
      countOverlay.classList.add("hidden");
      start(); NET.starting=false;
      grindSound(); beat();
    }
  },1000);
}
function onRoomMsg(m){
  if(m.t==="pos" && NET.oppo){
    NET.oppo.px=m.px; NET.oppo.py=m.py;
    const rec=Players.get("oppo_"+NET.room); if(rec){ rec.px=m.px; rec.py=m.py; }
  }
  else if(m.t==="spawn" && !NET.isHost && G.mode==="play"){
    const T=TYPES[m.k];
    G.targets.push({type:m.k,id:m.id,x:m.x,y:m.y,r:T.r,
      age:0,stand:T.standTime,popping:true,folding:false,stuck:false,blinking:false,
      face:Math.random()<0.5?-1:1, wob:Math.random()*6.28,
      skin:Math.random()<0.5?"#e8b48a":"#c98e62",
      shirt:["#e6a925","#4e54a3","#8a90e8","#caa64a","#6a70c0"][Math.floor(Math.random()*5)]});
  }
  else if(m.t==="clear"){
    const i=G.targets.findIndex(t=>t.id===m.id);
    if(i>=0){ dust(G.targets[i].x,G.targets[i].y,7,80); G.targets.splice(i,1); }
    if(NET.oppo){
      NET.oppo.score+=m.pts;
      const rec=Players.get("oppo_"+NET.room); if(rec) rec.score=NET.oppo.score;
    }
  }
  else if(m.t==="end"){
    NET.oppoFinal=m.score; updateBoard();
    if(NET.lineNames&&m.name){ delete NET.lineNames[m.name]; renderActiveLine(); }
  }
  else if(m.t==="fire"){
    // purely cosmetic ack from the opponent's weapon — no local state change needed
  }
  else if(m.t==="leave"){
    if(NET.oppo){ Players.delete("oppo_"+NET.room); NET.oppo=null; liveBoardEl.style.display="none"; }
    if(NET.lineNames&&m.name){ delete NET.lineNames[m.name]; renderActiveLine(); }
  }
}
function renderLiveBoard(){
  // Built straight off the Players Map so adding a 3rd/4th competitor later
  // is just more Map entries — this loop doesn't change.
  const me = Players.get(NET.id); if(me) me.score = G.score;
  const players = Array.from(Players.values()).filter(p=>p.you || p.id==="oppo_"+NET.room);
  players.sort((a,b)=>b.score-a.score);
  liveBoardEl.style.display="";
  liveBoardEl.innerHTML='<div class="lbTitle">Live</div>'+
    players.map((p,i)=>
      `<div class="lbRow${p.you?" you":""}">
        <span class="lbRank">${i+1}</span>
        <span class="lbName">${p.name}</span>
        <span class="lbScore">${p.score.toLocaleString()}</span>
      </div>`
    ).join("");
}
function updateBoard(){
  document.getElementById("p1name").textContent="אתה — "+NET.name;
  const p2n=document.getElementById("p2name"), p2s=document.getElementById("p2score");
  const p1=document.getElementById("p1col"), p2=document.getElementById("p2col");
  if(NET.room||NET.oppoFinal!=null){
    p2n.textContent=NET.oppo?NET.oppo.name:"היריב";
    if(NET.oppoFinal!=null){
      p2s.textContent=NET.oppoFinal.toLocaleString(); p2s.classList.remove("dim");
      p1.classList.toggle("winner",G.score>=NET.oppoFinal);
      p2.classList.toggle("winner",NET.oppoFinal>G.score);
    } else { p2s.textContent="..."; p1.classList.add("winner"); p2.classList.remove("winner"); }
  } else {
    p2n.textContent="שחקן #2"; p2s.textContent="—"; p2s.classList.add("dim");
    p1.classList.add("winner"); p2.classList.remove("winner");
  }
  document.querySelectorAll(".swarm").forEach(e=>e.remove());
  const w=p1.classList.contains("winner")?p1:(p2.classList.contains("winner")?p2:null);
  if(w) startSwarm(w);
}
function startSwarm(col){
  const s=document.createElement("div"); s.className="swarm";
  for(let i=0;i<8;i++){
    const r=document.createElement("div"); r.className="beeR";
    r.style.left=(6+Math.random()*86)+"%";
    r.style.animationDuration=(2.1+Math.random()*1.7)+"s";
    r.style.animationDelay=(Math.random()*2.6)+"s";
    const o=document.createElement("div"); o.className="beeO";
    o.style.animationDuration=(0.8+Math.random()*0.9)+"s";
    if(Math.random()<0.5) o.style.animationDirection="reverse";
    const b=document.createElement("div"); b.className="bee";
    b.style.setProperty("--r",(6+Math.random()*11)+"px");
    o.appendChild(b); r.appendChild(o); s.appendChild(r);
  }
  col.appendChild(s);
}
NET.defName=NET.name;
